import { NoticeManagerOptions } from './interfaces'

/**
 * NoticeManager - Handles the lifecycle and interactions of WordPress admin notices
 */
export class ArtsNoticeManager {
  private options: NoticeManagerOptions
  private boundClickHandler: ((event: MouseEvent) => void) | null = null
  private processingUrls: Set<string> = new Set()
  private isInitialized: boolean = false
  // Allow fetch to be injected for testing
  private fetchImplementation: typeof fetch

  /**
   * Create a new NoticeManager instance
   */
  constructor(
    options?: Partial<NoticeManagerOptions>,
    dependencies?: { fetch?: typeof fetch; autoInit?: boolean }
  ) {
    this.options = {
      dismissButtonSelector: '.notice-dismiss',
      noticeSelector: '.notice.is-dismissible',
      dismissUrlAttribute: 'data-dismiss-url',
      ...options
    }

    // Ensure fetch maintains its proper context
    this.fetchImplementation = dependencies?.fetch
      ? dependencies.fetch.bind(window)
      : fetch.bind(window)

    // Allow delayed initialization for testing
    if (dependencies?.autoInit !== false) {
      this.init()
    }
  }

  /**
   * Initialize event listeners
   */
  public init(): void {
    if (this.isInitialized) {
      this.cleanup() // Ensure we clean up any existing handlers first
    }

    this.boundClickHandler = this.handleDismissClick.bind(this)
    document.addEventListener('click', this.boundClickHandler)
    this.isInitialized = true
  }

  /**
   * Clean up event listeners and resources
   */
  public cleanup(): void {
    if (this.boundClickHandler) {
      document.removeEventListener('click', this.boundClickHandler)
      this.boundClickHandler = null
    }
    this.processingUrls.clear()
    this.isInitialized = false
  }

  /**
   * Handle dismiss button clicks
   */
  private handleDismissClick(event: MouseEvent): void {
    const target = event.target as HTMLElement
    if (!target) {
      return
    }

    // Use matches() for better selector compatibility
    if (!this.elementMatches(target, this.options.dismissButtonSelector)) {
      return
    }

    const notice = target.closest<HTMLElement>(this.options.noticeSelector)
    if (!notice) {
      return
    }

    const dismissUrl = notice.getAttribute(this.options.dismissUrlAttribute)
    if (!dismissUrl) {
      return
    }

    this.processDismissalWithDeduplication(dismissUrl, notice)
  }

  /**
   * Process dismissal with URL deduplication
   * Extracted for better testability
   */
  public processDismissalWithDeduplication(dismissUrl: string, noticeElement: HTMLElement): void {
    // Prevent processing the same URL multiple times
    if (this.processingUrls.has(dismissUrl)) {
      return
    }

    // Track this URL as being processed
    this.processingUrls.add(dismissUrl)

    // Process the dismissal
    this.dismissNotice(dismissUrl, noticeElement).catch(() => {}) // Catch errors to prevent unhandled promise rejections
  }

  /**
   * Check if an element matches a selector
   */
  private elementMatches(element: HTMLElement, selector: string): boolean {
    try {
      return element.matches(selector)
    } catch (e) {
      // Fallback for older browsers
      return (
        element.classList.contains(selector.replace('.', '')) ||
        element.id === selector.replace('#', '') ||
        Array.from(document.querySelectorAll(selector)).includes(element)
      )
    }
  }

  /**
   * Dismiss a notice via AJAX
   */
  private async dismissNotice(dismissUrl: string, noticeElement: HTMLElement): Promise<void> {
    try {
      const response = await this.fetchImplementation(dismissUrl)

      if (!response.ok) {
        throw new Error(`Failed to dismiss notice: ${response.status}`)
      }

      await response.text()

      // Use a more direct way to remove the element
      if (noticeElement.parentNode) {
        noticeElement.parentNode.removeChild(noticeElement)
      }
    } catch (error) {
      console.error('Notice dismissal failed:', error)
    } finally {
      // Remove this URL from the processing set
      this.processingUrls.delete(dismissUrl)
    }
  }

  /**
   * For testing only - check if a URL is currently being processed
   */
  public isProcessingUrl(url: string): boolean {
    return this.processingUrls.has(url)
  }
}
